import { useState } from 'react';
import { useStore } from '../store';
import { shallow } from 'zustand/shallow';
import { Play, CheckCircle2, XCircle, AlertCircle, Search, Bell, Settings } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const selector = (s) => ({ nodes: s.nodes, edges: s.edges });

export const TopNav = () => {
  const { nodes, edges } = useStore(selector, shallow);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const handleSubmit = async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const res = await fetch('http://127.0.0.1:8000/pipelines/parse', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nodes, edges }),
      });
      if (!res.ok) throw new Error(`Server error: ${res.status}`);
      const data = await res.json();
      setResult(data);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <div
        style={{
          height: '56px',
          background: 'var(--bg-surface)',
          borderBottom: '1px solid var(--border-subtle)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: '0 24px',
          zIndex: 10,
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <div style={{ fontSize: '14px', fontWeight: 600, color: 'var(--text-primary)' }}>
            Untitled Workflow
          </div>
          <div
            style={{
              padding: '4px 8px',
              background: 'rgba(255, 255, 255, 0.05)',
              borderRadius: '4px',
              fontSize: '11px',
              color: 'var(--text-tertiary)',
              display: 'flex',
              alignItems: 'center',
              gap: '6px',
            }}
          >
            <div style={{ width: 6, height: 6, borderRadius: '50%', background: 'var(--state-success)' }} />
            Saved
          </div>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', color: 'var(--text-secondary)' }}>
            <Search size={18} style={{ cursor: 'pointer' }} />
            <Bell size={18} style={{ cursor: 'pointer' }} />
            <Settings size={18} style={{ cursor: 'pointer' }} />
          </div>

          <div style={{ width: 1, height: 24, background: 'var(--border-subtle)' }} />

          <motion.button
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            onClick={handleSubmit}
            disabled={loading}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '8px',
              padding: '8px 16px',
              borderRadius: '6px',
              border: 'none',
              background: 'var(--accent-blue)',
              color: '#fff',
              fontSize: '13px',
              fontWeight: 500,
              cursor: loading ? 'not-allowed' : 'pointer',
              opacity: loading ? 0.7 : 1,
              fontFamily: 'inherit',
            }}
          >
            <Play size={16} fill="currentColor" />
            {loading ? 'Running...' : 'Deploy'}
          </motion.button>

          <div style={{ width: 32, height: 32, borderRadius: '50%', background: 'var(--accent-violet)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: '14px', fontWeight: 600, cursor: 'pointer' }}>
            VS
          </div>
        </div>
      </div>

      <AnimatePresence>
        {result && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            style={{
              position: 'fixed',
              inset: 0,
              background: 'rgba(0,0,0,0.6)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              zIndex: 100,
              backdropFilter: 'blur(4px)',
            }}
            onClick={() => setResult(null)}
          >
            <motion.div
              initial={{ scale: 0.95, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              exit={{ scale: 0.95, y: 20 }}
              style={{
                background: 'var(--bg-surface-elevated)',
                border: '1px solid var(--border-subtle)',
                borderRadius: '12px',
                padding: '24px',
                width: '360px',
                boxShadow: '0 24px 48px rgba(0,0,0,0.4)',
              }}
              onClick={(e) => e.stopPropagation()}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '24px' }}>
                <div style={{ width: 40, height: 40, borderRadius: '8px', background: 'rgba(59, 130, 246, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent-blue)' }}>
                  <Play size={20} />
                </div>
                <div>
                  <h2 style={{ margin: 0, fontSize: '16px', fontWeight: 600, color: 'var(--text-primary)' }}>Deployment Results</h2>
                  <p style={{ margin: '2px 0 0', fontSize: '13px', color: 'var(--text-tertiary)' }}>Pipeline parsing complete</p>
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '24px' }}>
                <div style={{ padding: '16px', background: 'var(--bg-app)', borderRadius: '8px', border: '1px solid var(--border-subtle)' }}>
                  <div style={{ fontSize: '24px', fontWeight: 600, color: 'var(--text-primary)', marginBottom: '4px' }}>{result.num_nodes}</div>
                  <div style={{ fontSize: '12px', color: 'var(--text-secondary)' }}>Nodes</div>
                </div>
                <div style={{ padding: '16px', background: 'var(--bg-app)', borderRadius: '8px', border: '1px solid var(--border-subtle)' }}>
                  <div style={{ fontSize: '24px', fontWeight: 600, color: 'var(--text-primary)', marginBottom: '4px' }}>{result.num_edges}</div>
                  <div style={{ fontSize: '12px', color: 'var(--text-secondary)' }}>Edges</div>
                </div>
              </div>

              <div
                style={{
                  padding: '16px',
                  borderRadius: '8px',
                  background: result.is_dag ? 'var(--state-success-bg)' : 'var(--state-error-bg)',
                  border: `1px solid ${result.is_dag ? 'rgba(16, 185, 129, 0.2)' : 'rgba(244, 63, 94, 0.2)'}`,
                  display: 'flex',
                  alignItems: 'flex-start',
                  gap: '12px',
                  marginBottom: '24px',
                }}
              >
                {result.is_dag ? <CheckCircle2 color="var(--state-success)" size={20} /> : <XCircle color="var(--state-error)" size={20} />}
                <div>
                  <div style={{ fontSize: '14px', fontWeight: 600, color: result.is_dag ? 'var(--state-success)' : 'var(--state-error)', marginBottom: '4px' }}>
                    {result.is_dag ? 'Valid Pipeline' : 'Cyclic Dependency Detected'}
                  </div>
                  <div style={{ fontSize: '13px', color: 'var(--text-secondary)', lineHeight: 1.4 }}>
                    {result.is_dag
                      ? 'The pipeline forms a valid Directed Acyclic Graph.'
                      : 'The pipeline contains a cycle and cannot be executed.'}
                  </div>
                </div>
              </div>

              <button
                onClick={() => setResult(null)}
                style={{
                  width: '100%',
                  padding: '10px',
                  background: 'var(--bg-app)',
                  border: '1px solid var(--border-strong)',
                  borderRadius: '6px',
                  color: 'var(--text-primary)',
                  fontSize: '13px',
                  fontWeight: 500,
                  cursor: 'pointer',
                  fontFamily: 'inherit',
                }}
              >
                Close
              </button>
            </motion.div>
          </motion.div>
        )}

        {error && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            style={{
              position: 'fixed',
              inset: 0,
              background: 'rgba(0,0,0,0.6)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              zIndex: 100,
              backdropFilter: 'blur(4px)',
            }}
            onClick={() => setError(null)}
          >
            <motion.div
              initial={{ scale: 0.95, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              exit={{ scale: 0.95, y: 20 }}
              style={{
                background: 'var(--bg-surface-elevated)',
                border: '1px solid rgba(244, 63, 94, 0.2)',
                borderRadius: '12px',
                padding: '24px',
                width: '360px',
                boxShadow: '0 24px 48px rgba(0,0,0,0.4)',
              }}
              onClick={(e) => e.stopPropagation()}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
                <div style={{ width: 40, height: 40, borderRadius: '8px', background: 'var(--state-error-bg)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--state-error)' }}>
                  <AlertCircle size={20} />
                </div>
                <div>
                  <h2 style={{ margin: 0, fontSize: '16px', fontWeight: 600, color: 'var(--text-primary)' }}>Connection Failed</h2>
                </div>
              </div>
              <div style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: '24px', lineHeight: 1.5 }}>
                {error}. Make sure the backend is running at localhost:8000.
              </div>
              <button
                onClick={() => setError(null)}
                style={{
                  width: '100%',
                  padding: '10px',
                  background: 'var(--bg-app)',
                  border: '1px solid var(--border-strong)',
                  borderRadius: '6px',
                  color: 'var(--text-primary)',
                  fontSize: '13px',
                  fontWeight: 500,
                  cursor: 'pointer',
                  fontFamily: 'inherit',
                }}
              >
                Dismiss
              </button>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};
